import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

const AppraisalForm = () => {
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    employeeName: "",
    department: "",
    period: "",
    rating: "",
    status: "Pending",
  });

  // Handle input change
  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  // Handle Save
  const handleSubmit = (e) => {
    e.preventDefault();

    const existing = JSON.parse(localStorage.getItem("appraisals")) || [];

    const newRecord = {
      id: Date.now(),
      ...formData
    };

    existing.push(newRecord);

    localStorage.setItem("appraisals", JSON.stringify(existing));

    alert("Appraisal Added Successfully");

    navigate("/dashboard/appraisal");
  };

  return (
    <div style={{ padding: "25px" }}>
      <h2>Add Employee Appraisal</h2>

      <form onSubmit={handleSubmit} style={{ marginTop: "20px", maxWidth: "500px" }}>

        <label>Employee Name</label>
        <input
          name="employeeName"
          value={formData.employeeName}
          onChange={handleChange}
          required
        />

        <label>Department</label>
        <input
          name="department"
          value={formData.department}
          onChange={handleChange}
          required
        />

        <label>Review Period</label>
        <input
          name="period"
          value={formData.period}
          onChange={handleChange}
          placeholder="Jan 2024 - Dec 2024"
          required
        />

        <label>Rating</label>
        <input
          type="number"
          step="0.1"
          name="rating"
          value={formData.rating}
          onChange={handleChange}
          required
        />

        <label>Status</label>
        <select
          name="status"
          value={formData.status}
          onChange={handleChange}
        >
          <option>Pending</option>
          <option>Approved</option>
          <option>Rejected</option>
        </select>

        <br /><br />

        <button type="submit">Save</button>

        <button
          type="button"
          style={{ marginLeft: "10px" }}
          onClick={() => navigate("/dashboard/appraisal")}
        >
          Cancel
        </button>

      </form>
    </div>
  );
};

export default AppraisalForm;
